body:
Running the following script

```bash
cat << EOF > test.v
module test (
	input clk, d,
	output q
);

	SB_IO #(
		/* OUTPUT_REGISTERED, OUTPUT_ALWAYS */
		.PIN_TYPE(6'b010100)
	) pin (
		.PACKAGE_PIN(q),
		.OUTPUT_CLK(clk),
		.D_OUT_0(d),
	);

endmodule
EOF
yosys -p "synth_ice40 -top test" -b json -o test.synth.json test.v
nextpnr-ice40 --json test.synth.json --write test.post.json
yosys test.post.json
```

results in yosys failing after encountering an assertion failure:

```
-- Parsing `test.post.json' using frontend `json' --

1. Executing JSON frontend.
Importing module top from JSON tree.
ERROR: Assert `!it2.first.empty()' failed in kernel/rtlil.cc:1853.
```

That is, [this assertion](https://github.com/YosysHQ/yosys/blob/6e907acf86d9ff0edd9a1c10274e62690e19e939/kernel/rtlil.cc#L1855). I am using `Yosys 0.20+70 (git sha1 6e907acf8, gcc 12.1.0 -fPIC -Os)` with `nextpnr-ice40 -- Next Generation Place and Route (Version nextpnr-0.3)`. Recompiling with `ENABLE_NDEBUG=1`, I have no problem converting back to verilog:

```verilog
module top(q, d, clk);
  wire _0_;
  input clk;
  wire clk;
  wire \clk$SB_IO_IN ;
  wire \clk$SB_IO_IN_$glb_clk ;
  input d;
  wire d;
  wire \d$SB_IO_IN ;
  output q;
  wire q;
  ICESTORM_LC #(
    .ASYNC_SR(1'h0),
    .CARRY_ENABLE(1'h0),
    .CIN_CONST(1'h0),
    .CIN_SET(1'h0),
    .DFF_ENABLE(1'h0),
    .LUT_INIT(16'h0001),
    .NEG_CLK(1'h0),
    .SET_NORESET(1'h0)
  ) _1_ (
    .O(_0_)
  );
  SB_GB _2_ (
    .GLOBAL_BUFFER_OUTPUT(\clk$SB_IO_IN_$glb_clk ),
    .USER_SIGNAL_TO_GLOBAL_BUFFER(\clk$SB_IO_IN )
  );
  SB_IO #(
    .IO_STANDARD("SB_LVCMOS"),
    .NEG_TRIGGER(1'h0),
    .PIN_TYPE(32'd1),
    .PULLUP(1'h0)
  ) \clk$sb_io  (
    .D_IN_0(\clk$SB_IO_IN ),
    .PACKAGE_PIN(clk)
  );
  SB_IO #(
    .IO_STANDARD("SB_LVCMOS"),
    .NEG_TRIGGER(1'h0),
    .PIN_TYPE(32'd1),
    .PULLUP(1'h0)
  ) \d$sb_io  (
    .D_IN_0(\d$SB_IO_IN ),
    .PACKAGE_PIN(d)
  );
  SB_IO #(
    .PIN_TYPE(6'h14)
  ) pin (
    .CLOCK_ENABLE(_0_),
    .D_OUT_0(\d$SB_IO_IN ),
    .OUTPUT_CLK(\clk$SB_IO_IN_$glb_clk ),
    .PACKAGE_PIN(q)
  );
endmodule
```

So perhaps this assert is unnecessary? Note that modules which don't explicitly instantiate an SB_IO do not have this problem (although I haven't tried other cells).

